// constants
const steps = [
  {
    id: "01",
    title: "User Journey Map",
    description: "Better a diamond with a flaw than a pebble without one."
  },
  {
    id: "02",
    title: "Digital Wireframe",
    description: "Better a diamond with a flaw than a pebble without one."
  },
  {
    id: "03",
    title: "Clickable Prototype",
    description: "Better a diamond with a flaw than a pebble without one."
  },
  {
    id: "04",
    title: "Visual Design",
    description: "Better a diamond with a flaw than a pebble without one."
  }
];

// ------------------------------ | PROCESS 2 | ------------------------------ //

export default function Process2() {
  return (
    <section className="bg-primary py-20 lg:py-28">
      <div className="mx-auto container px-4 sm:px-6 lg:px-8">
        {/* Header */}
        <div className="mx-auto mb-16 max-w-3xl text-center">
          <p className="mb-4 text-sm font-semibold uppercase tracking-[0.35em] text-yellow-500 sm:text-base">
            Process
          </p>

          <h2 className="mb-6 text-primary-foreground">How We Work</h2>

          <p className="mx-auto max-w-2xl text-base leading-8 text-primary-foreground/75 sm:text-lg">
            This is a big one and i consider it one of the most important things
            for a designer to get right.
          </p>
        </div>

        {/* Steps */}
        <div className="grid grid-cols-1 gap-10 sm:grid-cols-2 lg:grid-cols-4 lg:gap-8">
          {steps.map((step, index) => (
            <div key={step.id} className="text-center lg:text-left">
              {/* Number Box */}
              <div className="mb-7 flex justify-center lg:justify-start">
                <div className="flex h-20 w-20 items-center justify-center bg-background">
                  <span className="text-4xl font-bold text-yellow-500">
                    {step.id}
                  </span>
                </div>
              </div>

              {/* Title */}
              <h5 className="mb-2 font-semibold text-primary-foreground">
                {index + 1}. {step.title}
              </h5>

              {/* Description */}
              <p className="text-base text-primary-foreground/75">
                {step.description}
              </p>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}
